//B. Pleasant Pairs #include<bits/stdc++.h>using namespace std;#define int long long int void fast_io() {    std::ios_base::sync_with_stdio(false);    std::cin.tie(NULL);    std::cout.tie(NULL);} signed main(){    fast_io();    int t;    cin>>t;    while(t--){        int n;        cin>>n;        vector<pair<int,int>>arr(n);        for(int i=0;i<n;i++){            cin>>arr[i].first;            arr[i].second=i+1;        }        sort(arr.begin(),arr.end());        int khushi=0;        for(int i=0;i<n;i++){            for(int j=i+1;j<n;j++){                if((arr[i].first)*arr[j].first==arr[i].second+arr[j].second){                    khushi++;                }                if((arr[i].first)*(arr[j].first)>=2*n){                    break;                }            }        }        cout<<khushi<<endl;     }}